// Transforma a string 'stdout' em campos reais do n8n
const output = JSON.parse($input.item.json.stdout);
return output;

// 1. Gera o timestamp para prefixo de arquivos
const agora = new Date();
const pad = (n, size) => String(n).padStart(size, "0");

const timestamp = 
  agora.getFullYear() +
  pad(agora.getMonth() + 1, 2) +
  pad(agora.getDate(), 2) +
  pad(agora.getHours(), 2) +
  pad(agora.getMinutes(), 2) +
  pad(agora.getSeconds(), 2) +
  pad(agora.getMilliseconds(), 3);

// 2. Define as regras de validação do Payload
const CAMPOS_PERMITIDOS = [
  'pdf_url', 'PDF_URL', 
  'page_from', 'page_to', 
  'dpi', 'image_format', 
  'quality', 'page_mode', 
  'merge_pages'
];

return $input.all().map(item => {
  // Suporta entrada via Webhook Body ou direta
  const body = item.json.body || item.json; 
  const camposEnviados = Object.keys(body);

  // --- VALIDAÇÃO 01: Campos Desconhecidos ---
  // Verifica se o usuário enviou algo que não está na lista permitida (ex: erro de digitação)
  const camposInvalidos = camposEnviados.filter(campo => !CAMPOS_PERMITIDOS.includes(campo));

  if (camposInvalidos.length > 0) {
    throw new Error(`Erro de Payload: O(s) campo(s) [${camposInvalidos.join(', ')}] não são reconhecidos por esta API.`);
  }

  // --- VALIDAÇÃO 02: Campos Obrigatórios ---
  const pdfUrl = body.pdf_url || body.PDF_URL;
  if (!pdfUrl) {
    throw new Error("Erro de Payload: O campo 'pdf_url' é obrigatório.");
  }

  // --- VALIDAÇÃO 03: Tipagem básica (Opcional, mas recomendada) ---
  if (body.page_from && isNaN(body.page_from)) throw new Error("O campo 'page_from' deve ser um número ou string numérica.");

  // --- NORMALIZAÇÃO ---
  const filePrefix = timestamp;

  return {
    json: {
      // Inputs Normalizados (Garante que o Python receba sempre o mesmo nome de chave)
      PDF_URL: pdfUrl,
      PAGE_FROM: String(body.page_from || "1"),
      PAGE_TO: String(body.page_to || "1"),

      // Campos Gerados Dinamicamente
      FILE_PREFIX: filePrefix,
      DPI: String(body.dpi || "300"),
      IMAGE_FORMAT: (body.image_format || "png").toLowerCase(),
      QUALITY: String(body.quality || "95"),
      PAGE_MODE: (body.page_mode || "all").toLowerCase(),

      // Caminhos de Sistema
      OUT_DIR: `/n8n_data/pdf/pdf_pages/${filePrefix}`,
      PDF_DOWNLOAD_PATH: `/n8n_data/pdf/${filePrefix}.pdf`,

      // Configurações Fixas de Segurança/Saída
      OUTPUT_TYPE: "local",
      BASE64_PREFIX: false,
      MAX_PAGES: 10,
      MERGE_PAGES: !!body.merge_pages // Converte para booleano real
    }
  };
});

